sql:
SELECT AVG(volume_mm3) AS average_roi_volume
FROM rois
WHERE network_id = 1;

SELECT roi_label, roi_name
FROM rois
WHERE roi_id = 1;

SELECT hemisphere, COUNT(roi_id) AS num_rois
FROM rois
GROUP BY hemisphere;

SELECT COUNT(DISTINCT roi_id) AS roi_count
FROM study_rovers
WHERE study_id = 1;

SELECT COUNT(*) AS roi_count
FROM rois
WHERE hemisphere = 'Left' AND volume_mm3 > 100;

SELECT DISTINCT T1.subject_name
FROM subjects AS T1
INNER JOIN sessions AS T2 ON T1.subject_id = T2.subject_id;

SELECT roi_id, COUNT(session_id) AS number_of_sessions
FROM roi_sessions
GROUP BY roi_id;

SELECT AVG(volume_mm3) AS average_volume
FROM rois
WHERE network_id = 1 AND hemisphere = 'Left';

